#include <bits/stdc++.h>
using namespace std;

const int N = 1e6 + 5;
const int MOD = 100003;

int dis[N], cnt[N];
vector<int> e[N];
int n, m;

void BFS(int start) {
    memset(dis, -1, sizeof(dis));
    memset(cnt, 0, sizeof(cnt));

    queue<int> q;
    dis[start] = 0;
    cnt[start] = 1;
    q.push(start);

    while (!q.empty()) {
        int u = q.front();
        q.pop();

        for (int v : e[u]) {
            if (dis[v] == -1) {
                dis[v] = dis[u] + 1;
                cnt[v] = cnt[u];
                q.push(v);
            } else if (dis[v] == dis[u] + 1) {
                cnt[v] = (cnt[v] + cnt[u]) % MOD;
            }
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> m;
    for (int i = 1; i <= m; i++) {
        int u, v;
        cin >> u >> v;
        e[u].push_back(v);
        e[v].push_back(u);
    }

    BFS(1);

    for (int i = 1; i <= n; i++) {
        cout << (dis[i] == -1 ? 0 : cnt[i]) << '\n';
    }

    return 0;
}
